from collections import defaultdict

def detect_loops(messages, max_turns=20):
    speaker_turns = defaultdict(list)
    for i, msg in enumerate(messages):
        speaker = msg.get('name', 'unknown')
        speaker_turns[speaker].append(i)

    for speaker, turns in speaker_turns.items():
        if len(turns) > max_turns:
            recent_msgs = [messages[t]['content'][-100:] for t in turns[-3:]]
            if len(set(recent_msgs)) < 2:
                return {'issue': 'infinite_loop', 'speaker': speaker}
    return None

import re

def detect_unsafe_code(code_content):
    dangerous_patterns = [
        r'exec\(', r'eval\(', r'__import__\(',
        r'os\.system\(', r'subprocess\.',
        r'open\(.*?,? ?"w"', r'rm\s+-rf',
        r'del\s+sys\.', r'\brm\b.*-rf'
    ]
    for pattern in dangerous_patterns:
        if re.search(pattern, code_content, re.IGNORECASE):
            return {'issue': 'unsafe_code', 'pattern': pattern}
    return None

def track_token_usage(messages, model='gpt-4', budget=10000):
    total_tokens = 0
    for msg in messages:
        content = msg.get('content', '')
        total_tokens += len(content.split()) * 1.3  # Rough estimation

    if total_tokens > budget:
        return {
            'issue': 'token_exceeded',
            'current': total_tokens,
            'budget': budget
        }
    return None

