import subprocess
import tempfile
import os

def safe_execute_code(code):
    with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as f:
        f.write(code)
        temp_file = f.name

    try:
        result = subprocess.run(
            ['python', temp_file],
            capture_output=True,
            timeout=30,
            cwd='/tmp'  # Sandboxed directory
        )
        os.unlink(temp_file)
        return {
            'stdout': result.stdout.decode(),
            'stderr': result.stderr.decode(),
            'safe': True
        }
    except subprocess.TimeoutExpired:
        os.unlink(temp_file)
        return {'error': 'Execution timeout', 'safe': False}
